  1	import * as React from 'react';
  2	import { Server, ServerForm } from '../../../types/IstioObjects';
  3	import { Tbody, Td, Th, Thead, Tr, Table, ThProps } from '@patternfly/react-table';
  4	import { kialiStyle } from 'styles/StyleUtils';
  5	import { PFColors } from '../../../components/Pf/PfColors';
  6	import { Button, ButtonVariant } from '@patternfly/react-core';
  7	import { ServerBuilder, protocols } from './ServerBuilder';
  8	import { KialiIcon } from 'config/KialiIcon';
  9	
 10	type ServerListProps = {
 11	  onChange: (server: Server[], serverForm: ServerForm[]) => void;
 12	  serverForm: ServerForm[];
 13	  serverList: Server[];
 14	};
 15	
 16	const noServerStyle = kialiStyle({
 17	  color: PFColors.Red100,
 18	  textAlign: 'center'
 19	});
 20	
 21	const columns: ThProps[] = [
 22	  {
 23	    title: 'Servers'
 24	  },
 25	  {
 26	    title: ''
 27	  }
 28	];
 29	
 30	const addServerStyle = kialiStyle({
 31	  marginLeft: '0.5rem',
 32	  marginTop: '0.25rem'
 33	});
 34	
 35	export const ServerList: React.FC<ServerListProps> = (props: ServerListProps) => {
 36	  const onAddServer = (): void => {
 37	    const newServerForm: ServerForm = {
 38	      hosts: [],
 39	      number: '',
 40	      protocol: protocols[0],
 41	      name: '',
 42	      tlsMode: '',
 43	      tlsServerCertificate: '',
 44	      tlsPrivateKey: '',
 45	      tlsCaCertificate: ''
 46	    };
 47	
 48	    const sf = props.serverForm;
 49	    sf.push(newServerForm);
 50	
 51	    const newServer: Server = {
 52	      hosts: [],
 53	      port: {
 54	        number: 70000,
 55	        name: '',
 56	        protocol: 'HTTP'
 57	      }
 58	    };
 59	
 60	    const s = props.serverList;
 61	    s.push(newServer);
 62	
 63	    props.onChange(s, sf);
 64	  };
 65	
 66	  const onRemoveServer = (index: number): void => {
 67	    const serverList = props.serverList;
 68	    serverList.splice(index, 1);
 69	
 70	    const serverForm = props.serverForm;
 71	    serverForm.splice(index, 1);
 72	
 73	    props.onChange(serverList, serverForm);
 74	  };
 75	
 76	  const onChange = (serverForm: ServerForm, i: number): void => {
 77	    const serversForm = props.serverForm;
 78	    serversForm[i] = serverForm;
 79	
 80	    const servers = props.serverList;
 81	    const newServer = createNewServer(serverForm);
 82	
 83	    if (typeof newServer !== 'undefined') {
 84	      servers[i] = newServer;
 85	    }
 86	
 87	    props.onChange(servers, serversForm);
 88	  };
 89	
 90	  const createNewServer = (serverForm: ServerForm): Server | undefined => {
 91	    if (serverForm.hosts.length === 0) return;
 92	    if (serverForm.number.length === 0 || isNaN(Number(serverForm.number))) return;
 93	    if (serverForm.name.length === 0) return;
 94	
 95	    const server: Server = {
 96	      hosts: serverForm.hosts,
 97	      port: { number: Number(serverForm.number), name: serverForm.name, protocol: serverForm.protocol },
 98	      tls:
 99	        serverForm.protocol === 'HTTPS' || serverForm.protocol === 'TLS'
100	          ? {
101	              mode: serverForm.tlsMode,
102	              serverCertificate: serverForm.tlsServerCertificate,
103	              privateKey: serverForm.tlsPrivateKey,
104	              caCertificates: serverForm.tlsCaCertificate
105	            }
106	          : undefined
107	    };
108	
109	    return server;
110	  };
111	
112	  return (
113	    <>
114	      <Table aria-label="Server List">
115	        <Thead>
116	          <Tr>
117	            {columns.map((column, index) => (
118	              <Th key={`column_${index}`} dataLabel={column.title}>
119	                {column.title}
120	              </Th>
121	            ))}
122	          </Tr>
123	        </Thead>
124	        <Tbody>
125	          {props.serverForm.length > 0 ? (
126	            <>
127	              {props.serverForm.map((server, index) => (
128	                <ServerBuilder
129	                  key={`server_builder_${index}`}
130	                  server={server}
131	                  onRemoveServer={onRemoveServer}
132	                  index={index}
133	                  onChange={onChange}
134	                ></ServerBuilder>
135	              ))}
136	            </>
137	          ) : (
138	            <Tr>
139	              <Td colSpan={columns.length}>
140	                <div className={noServerStyle}>No Servers defined</div>
141	              </Td>
142	            </Tr>
143	          )}
144	        </Tbody>
145	      </Table>
146	
147	      <Button
148	        name="addServer"
149	        variant={ButtonVariant.link}
150	        icon={<KialiIcon.AddMore />}
151	        onClick={onAddServer}
152	        className={addServerStyle}
153	      >
154	        Add Server to Servers List
155	      </Button>
156	    </>
157	  );
158	};

